+const fn scenario_budgets_us(scenario: ArchiveScenario) -> (u64, u64) {
+    match scenario {
+        ArchiveScenario::BatchNoAttachments { .. } => (250_000, 300_000),
+        _ => (25_000, 30_000),
+    }
+}
